import androidx.preference.Preference
import androidx.preference.PreferenceCategory
import androidx.preference.PreferenceGroup
import androidx.preference.PreferenceScreen
import com.ichi2.anki.R
import com.ichi2.anki.cardviewer.ViewerCommand
import com.ichi2.anki.cardviewer.ViewerCommandCategory
import com.ichi2.anki.reviewer.MappableBinding.Companion.toPreferenceString
import com.ichi2.preferences.ControlPreference

class ControlsSettingsFragment : SettingsFragment() {
    override val preferenceResource: Int
        get() = R.xml.preferences_controls
    override val analyticsScreenNameConstant: String
        get() = "prefs.controls"

    override fun initSubscreen() {
        val screen = preferenceScreen as PreferenceScreen

        // Remove the placeholder category from XML
        val placeholderCategory = screen.findPreference<PreferenceCategory>(requireContext().getString(R.string.controls_command_mapping_cat_key))
        placeholderCategory?.let { screen.removePreference(it) }

        // Add controlled preferences grouped by category
        addControlPreferencesByCategory(screen)
    }

    /** Attaches all possible [ControlPreference] elements to a [PreferenceScreen], grouped by category */
    private fun addControlPreferencesByCategory(screen: PreferenceScreen) {
        for (category in ViewerCommandCategory.all()) {
            val categoryPreference = PreferenceCategory(screen.context)
            categoryPreference.title = screen.context.getString(category.resourceId)
            categoryPreference.key = "command_category_${category.key}"
            screen.addPreference(categoryPreference)

            val commandsInCategory = ViewerCommand.values().filter { it.category == category }
            for (command in commandsInCategory) {
                val preference = ControlPreference(screen.context).apply {
                    setTitle(command.resourceId)
                    key = command.preferenceKey
                    setDefaultValue(command.defaultValue.toPreferenceString())
                }
                categoryPreference.addPreference(preference)
            }
        }
    }
}"}

