class ViewerCommandTest {

    @Test
    fun preference_keys_are_not_changed() {
        val names = Joiner.on(", ").join(ViewerCommand.values().map { x -> x.preferenceKey })

        // NONE OF THESE SHOULD BE CHANGED OR A USER WILL LOSE THE ASSOCIATED PREFERENCES
        // Adds are acceptable
        // Deletes are acceptable if the binding should no longer exist
        assertEquals(
            "binding_SHOW_ANSWER, binding_FLIP_OR_ANSWER_EASE1, " +
                "binding_FLIP_OR_ANSWER_EASE2, binding_FLIP_OR_ANSWER_EASE3, binding_FLIP_OR_ANSWER_EASE4, " +
                "binding_UNDO, binding_EDIT, binding_MARK, binding_BURY_CARD, " +
                "binding_SUSPEND_CARD, binding_DELETE, binding_PLAY_MEDIA, " +
                "binding_EXIT, binding_BURY_NOTE, binding_SUSPEND_NOTE, binding_TOGGLE_FLAG_RED, " +
                "binding_TOGGLE_FLAG_ORANGE, binding_TOGGLE_FLAG_GREEN, binding_TOGGLE_FLAG_BLUE, " +
                "binding_TOGGLE_FLAG_PINK, binding_TOGGLE_FLAG_TURQUOISE, binding_TOGGLE_FLAG_PURPLE, " +
                "binding_UNSET_FLAG, binding_PAGE_UP, binding_PAGE_DOWN, binding_TAG, binding_CARD_INFO, binding_ABORT_AND_SYNC, " +
                "binding_RECORD_VOICE, binding_REPLAY_VOICE, binding_TOGGLE_WHITEBOARD, binding_CLEAR_WHITEBOARD, " +
                "binding_CHANGE_WHITEBOARD_PEN_COLOR, binding_SHOW_HINT, binding_SHOW_ALL_HINTS, binding_ADD_NOTE, " +
                "binding_RESCHEDULE_NOTE",
            names
        )
    }

    @Test
    fun all_commands_have_category() {
        // Verify that every ViewerCommand has been assigned a category
        for (command in ViewerCommand.values()) {
            assertTrue(
                "Command ${command.name} has not been assigned to a category. " +
                    "Ensure all commands are properly categorized for better UX in the controls preferences.",
                ViewerCommandCategory.all().contains(command.category)
            )
        }
    }

    @Test
    fun category_counts_match_expected() {
        // Verify that each category has the expected number of commands
        // This helps ensure all commands have been categorized correctly
        val categoryCounts = ViewerCommand.values().groupBy { it.category }.mapValues { it.value.size }

        assertEquals("Answer buttons should have 5 commands", 5, categoryCounts[ViewerCommandCategory.ANSWER_BUTTONS])
        assertEquals("Flags should have 8 commands", 8, categoryCounts[ViewerCommandCategory.FLAGS])
        assertEquals("Current card / note should have 8 commands", 8, categoryCounts[ViewerCommandCategory.CURRENT_CARD_OR_NOTE])
        assertEquals("Whiteboard should have 3 commands", 3, categoryCounts[ViewerCommandCategory.WHITEBOARD])
        assertEquals("Navigation should have 5 commands", 5, categoryCounts[ViewerCommandCategory.NAVIGATION])
        assertEquals("Misc should have 5 commands", 5, categoryCounts[ViewerCommandCategory.MISC])

